mapper.select:
SELECT c.id AS classId, c.class_name AS className, u1.user_name AS charger, co.course_name AS courseName, co.id AS courseId,
FROM `user` u LEFT JOIN user_role ur ON u.id = ur.user_id LEFT JOIN user_class uc ON u.id = uc.user_id LEFT JOIN class c ON c.id = uc.class_id LEFT JOIN course co ON co.id = c.course_id LEFT JOIN `user` u1 ON c.user_id = u1.id
AND ur.role_id = #{roleId}
ORDER BY u.id DESC LIMIT #{page},#{pageSize}
